   107→// resolvePort attempts to turn an IntOrString port reference into a concrete port number.
   108→// If portReference has an int value, it is treated as a literal, and simply returns that value.
   109→// If portReference is a string, an attempt is first made to parse it as an integer.  If that fails,
   110→// an attempt is made to find a port with the same name in the container spec.
   111→// If a port with the same name is found, it's ContainerPort value is returned.  If no matching
   112→// port is found, an error is returned.
   113→func resolvePort(portReference intstr.IntOrString, container *v1.Container) (int, error) {
   114→	if portReference.Type == intstr.Int {
   115→		return portReference.IntValue(), nil
   116→	}
   117→	portName := portReference.StrVal
   118→	port, err := strconv.Atoi(portName)
   119→	if err == nil {
   120→		return port, nil
   121→	}
   122→	for _, portSpec := range container.Ports {
   123→		if portSpec.Name == portName {
   124→			return int(portSpec.ContainerPort), nil
   125→		}
   126→	}
   127→	return -1, fmt.Errorf("couldn't find port: %v in %v", portReference, container)
