   224→	if err == nil {
   225→		return PodAdmitResult{Admit: true}
   226→	}
   227→	return PodAdmitResult{
   228→		Admit:   false,
   229→		Reason:  AppArmorNotAdmittedReason,
   230→		Message: fmt.Sprintf("Cannot enforce AppArmor: %v", err),
   231→	}
   232→}
